const errors = $('Supabase → Error Logs').all().map(i => i.json);
const stuck = $('Supabase → Stuck Tasks').all().map(i => i.json);
const project = $('Called by Agent').first().json?.chatInput || 'profit';

return [{ json: {
  project,
  error_logs: Array.isArray(errors) ? errors : [],
  error_count: Array.isArray(errors) ? errors.length : 0,
  stuck_tasks: Array.isArray(stuck) ? stuck : [],
  stuck_count: Array.isArray(stuck) ? stuck.length : 0,
  checked_at: new Date().toISOString()
} }];

const merged = $('Merge Errors + Stuck').first().json;
const analysis = $input.first().json.content?.[0]?.text || '{}';

let parsed = {};
try {
  const cleaned = analysis.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { raw_analysis: analysis };
}

return [{ json: {
  status: 'completed',
  workflow: '10_error_monitor',
  project: merged.project,
  total_errors: merged.error_count,
  total_stuck: merged.stuck_count,
  summary: parsed.summary || 'Analysis complete',
  health_score: parsed.health_score || 'N/A',
  errors_grouped: parsed.errors_grouped || {},
  stuck_tasks: parsed.stuck_tasks || [],
  patterns: parsed.patterns || [],
  recommended_fixes: parsed.recommended_fixes || [],
  priority_actions: parsed.priority_actions || [],
  completedAt: new Date().toISOString()
} }];
